def findAnagrams(self, s, p):
    need = Counter(p)
    have = Counter()
    formed, required = 0, len(need)
    left = 0
    result = []
    for right in range(len(s)):
        c = s[right]
        have[c] = have.get(c, 0) + 1
        if c in need and have[c] == need[c]:
            formed += 1
        if right - left + 1 > len(p):
            lc = s[left]
            if lc in need and have[lc] == need[lc]:
                formed -= 1
            have[lc] -= 1
            if have[lc] == 0:
                del have[lc]
            left += 1
        if formed == required:
            result.append(left)
    return result
